  ('locality-814ced5a-moex-00052', 'locality-814ced5a', 'locality-814ced5a-moex-111-b3f42868', 'sub-locality-814ced5a-02', NULL, 'single_choice', '年特種考試地方政府公務人員考試試題 代號：2501 共50題，每題2分，須用2B鉛筆在試卡上依題號清楚劃記，於本試題上作答者，不予計分。', '["", "", "", ""]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:35:28+00:00", "source_pdf_sha1": "d68df4214d19", "answer_pdf_sha1": "7ccb5eb08e6d", "source_family": "moex-gov-tw", "moex": {"exam_code": "111190", "c": "506", "s": "0207", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "公民與英文", "year": "111", "exam_name": "111年特種考試地方政府公務人員考試", "original_question_number": 111, "answer_corrected": false, "flags": ["answer_missing", "incomplete_options"], "civil_slug": "locality", "civil_category": "圖書資訊管理"}'::jsonb, NULL),
  ('locality-814ced5a-moex-00053', 'locality-814ced5a', 'locality-814ced5a-moex-111-b3f42868', 'sub-locality-814ced5a-02', NULL, 'single_choice', '關於我國勞動參與率的敘述，下列何者正確？', '["勞動參與率是指勞動力占20歲以上民間人口的比率", "無論是就業者或失業者的增減，都會影響勞動參與率的升降", "近五年來，我國女性的勞動參與率已經和男性達到相同水準", "近五年來，我國平均勞動參與率已經達到七成"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:35:28+00:00", "source_pdf_sha1": "d68df4214d19", "answer_pdf_sha1": "7ccb5eb08e6d", "source_family": "moex-gov-tw", "moex": {"exam_code": "111190", "c": "506", "s": "0207", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "公民與英文", "year": "111", "exam_name": "111年特種考試地方政府公務人員考試", "original_question_number": 1, "answer_corrected": false, "flags": [], "civil_slug": "locality", "civil_category": "圖書資訊管理"}'::jsonb, NULL),
  ('locality-814ced5a-moex-00054', 'locality-814ced5a', 'locality-814ced5a-moex-111-b3f42868', 'sub-locality-814ced5a-02', NULL, 'single_choice', '傳統宮廟的遶境祈福活動，原來應該是全村熱鬧共襄盛舉，但位於都市內的著名宮廟辦理遶境活動， 常惹來部分社區民眾的抱怨與抗議，若不是抗議過於吵鬧，就是檢舉深夜燃放炮竹，有公共危險之虞， 甚至懷疑宮廟成員有黑道背景……等。下列何者最適合用以解釋上述狀況？', '["傳統文化與快速變遷社會的矛盾", "主流文化被少數文化所歧視與揚棄", "地方文化對全球文化的反抗", "民眾的社區意識紛紛抬頭"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:35:28+00:00", "source_pdf_sha1": "d68df4214d19", "answer_pdf_sha1": "7ccb5eb08e6d", "source_family": "moex-gov-tw", "moex": {"exam_code": "111190", "c": "506", "s": "0207", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "公民與英文", "year": "111", "exam_name": "111年特種考試地方政府公務人員考試", "original_question_number": 2, "answer_corrected": true, "flags": ["answer_corrected_skip_v1"], "civil_slug": "locality", "civil_category": "圖書資訊管理"}'::jsonb, NULL),
  ('locality-814ced5a-moex-00055', 'locality-814ced5a', 'locality-814ced5a-moex-111-b3f42868', 'sub-locality-814ced5a-02', NULL, 'single_choice', '某國自1980年代即開始實施育嬰假制度，配偶雙方各有三個月互不能轉讓的獨立育嬰假，期間可 領八成的薪資。此制度讓雙親共同承擔照顧新生兒的責任，據統計該國夫、妻請領育嬰假的比例 分別為45.6%與54.5%，相較亞洲國家兩性請育嬰假的比例更為均衡。前文所述最適合用下列那一 個概念說明？', '["玻璃天花板", "性別主流化", "性別多元化", "性別刻板印象"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:35:28+00:00", "source_pdf_sha1": "d68df4214d19", "answer_pdf_sha1": "7ccb5eb08e6d", "source_family": "moex-gov-tw", "moex": {"exam_code": "111190", "c": "506", "s": "0207", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "公民與英文", "year": "111", "exam_name": "111年特種考試地方政府公務人員考試", "original_question_number": 3, "answer_corrected": false, "flags": [], "civil_slug": "locality", "civil_category": "圖書資訊管理"}'::jsonb, NULL)
